import { useState } from "react";
import toast from "react-hot-toast";
import api from "../../api/client";
import { useAppStore } from "../../store/appStore";
import { validateEmailOffline } from "../../utils/offlineValidation";

export default function ValidateTab() {
  const { online, fetchSubscription, openWebsite } = useAppStore();
  const [email, setEmail] = useState("");
  const [enableSMTP, setEnableSMTP] = useState(false);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const onValidate = async () => {
    setLoading(true);
    try {
      let payload;
      if (online) {
        const response = await api.post("/validate/email", { email, enableSMTP });
        payload = {
          email,
          ...response.data,
          source: "server",
          createdAt: new Date().toISOString(),
        };
      } else {
        payload = {
          ...validateEmailOffline(email),
          timeTakenMs: 0,
          source: "offline",
          createdAt: new Date().toISOString(),
        };
      }

      setResult(payload);
      await window.desktop.cache.add(payload);
      if (online) fetchSubscription();
      toast.success("Validation complete");
    } catch (err) {
      const message = err?.response?.data?.message || "Validation failed";
      toast.error(message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="card space-y-4">
      <div className="flex flex-wrap items-center justify-between gap-2">
        <h3 className="text-lg font-semibold">Single Email Validation</h3>
        <button className="btn-outline" onClick={() => openWebsite("/pricing")}>Buy Subscription</button>
      </div>

      <input className="input" placeholder="Enter email address" value={email} onChange={(e) => setEmail(e.target.value)} />
      <label className="flex items-center gap-2 text-sm">
        <input type="checkbox" checked={enableSMTP} onChange={(e) => setEnableSMTP(e.target.checked)} disabled={!online} />
        Enable server verification (uses 1 credit)
      </label>

      <div className="flex gap-2">
        <button className="btn-primary" onClick={onValidate} disabled={loading || !email}>{loading ? "Validating..." : "Validate Email"}</button>
        <button className="btn-outline" onClick={() => { setEmail(""); setResult(null); }}>Clear</button>
      </div>

      {result && (
        <div className="rounded-lg border border-slate-200 bg-slate-50 p-4 text-sm">
          <div className="mb-2 flex items-center gap-2">
            <span className={`rounded px-2 py-1 text-xs font-semibold ${result.isValid ? "bg-emerald-100 text-emerald-700" : "bg-red-100 text-red-700"}`}>
              {result.isValid ? "Valid" : "Invalid"}
            </span>
            <span>{result.reason}</span>
          </div>
          <p>Time taken: {result.timeTakenMs || 0} ms</p>
          <p>Credit cost: {result.creditCost ?? 0}</p>
          <button className="mt-2 text-brand-700 hover:underline" onClick={() => navigator.clipboard.writeText(JSON.stringify(result, null, 2))}>Copy Result</button>
        </div>
      )}
    </div>
  );
}
